import React, { useState, useEffect } from 'react';
import api from '../services/api';

const FormularioCampesena = ({ formData, setFormData, instructoresVisibles, handleInstructorChange }) => {
  const [tiposPrograma, setTiposPrograma] = useState([]);
  const [campesenaData, setCampesenaData] = useState({
    duracion_meses: '',
    instructores: formData.instructores_campesena || [
      { tipo: '', nombre: '', correo: '', celular: '', fechas: ['', '', '', '', ''] },
      { tipo: '', nombre: '', correo: '', celular: '', fechas: ['', '', '', '', ''] }
    ]
  });

  useEffect(() => {
    cargarTiposPrograma();
  }, []);

  const cargarTiposPrograma = async () => {
    try {
      const response = await api.get('/tipos-programa');
      setTiposPrograma(response.data.data || []);
    } catch (error) {
      console.error('Error cargando tipos de programa:', error);
    }
  };

  const handleCampesenaChange = (e, index, campo) => {
    const nuevosInstructores = [...campesenaData.instructores];
    nuevosInstructores[index][campo] = e.target.value;
    setCampesenaData({ ...campesenaData, instructores: nuevosInstructores });
    setFormData({ ...formData, instructores_campesena: nuevosInstructores });
  };

  const handleFechaChange = (e, index, mesIndex) => {
    const nuevosInstructores = [...campesenaData.instructores];
    nuevosInstructores[index].fechas[mesIndex] = e.target.value;
    setCampesenaData({ ...campesenaData, instructores: nuevosInstructores });
    setFormData({ ...formData, instructores_campesena: nuevosInstructores });
  };

  return (
    <div style={styles.container}>
      {/* DURACIÓN */}
      <div style={styles.section}>
        <h3 style={styles.sectionTitle}>Duración</h3>
        <div style={styles.formGroup}>
          <label style={styles.label}>Duración (meses):</label>
          <input 
            type="number"
            value={campesenaData.duracion_meses}
            onChange={(e) => {
              setCampesenaData({ ...campesenaData, duracion_meses: e.target.value });
              setFormData({ ...formData, duracion_meses: e.target.value });
            }}
            style={styles.input}
            placeholder="5"
            min="1"
            max="5"
            required
          />
          <small style={styles.hint}>Para Campesena, máximo 5 meses</small>
        </div>
      </div>

      {/* INSTRUCTORES */}
      <div style={styles.section}>
        <h3 style={styles.sectionTitle}>Instructores Adicionales</h3>
        
        {/* Instructor 1 */}
        {instructoresVisibles.primerInstructor && (
          <div style={styles.instructorBox}>
            <h4 style={styles.instructorTitle}>Instructor {instructoresVisibles.primerInstructor}</h4>
            
            <div style={styles.formGroup}>
              <label style={styles.label}>Nombre Completo:</label>
              <input
                type="text"
                value={campesenaData.instructores[0]?.nombre || ''}
                onChange={(e) => handleCampesenaChange(e, 0, 'nombre')}
                style={styles.input}
                placeholder="Nombre completo"
                required
              />
            </div>

            <div style={styles.row}>
              <div style={styles.half}>
                <label style={styles.label}>Correo:</label>
                <input
                  type="email"
                  value={campesenaData.instructores[0]?.correo || ''}
                  onChange={(e) => handleCampesenaChange(e, 0, 'correo')}
                  style={styles.input}
                  placeholder="correo@ejemplo.com"
                  required
                />
              </div>
              <div style={styles.half}>
                <label style={styles.label}>Celular:</label>
                <input
                  type="tel"
                  value={campesenaData.instructores[0]?.celular || ''}
                  onChange={(e) => handleCampesenaChange(e, 0, 'celular')}
                  style={styles.input}
                  placeholder="3001234567"
                  required
                />
              </div>
            </div>

            <h5 style={styles.fechasTitle}>Fechas de Formación (Meses 1-5)</h5>
            <div style={styles.fechasGrid}>
              {[1, 2, 3, 4, 5].map((mes) => (
                <div key={mes} style={styles.fechaBox}>
                  <label style={styles.label}>Mes {mes}:</label>
                  <input
                    type="date"
                    value={campesenaData.instructores[0]?.fechas[mes-1] || ''}
                    onChange={(e) => handleFechaChange(e, 0, mes-1)}
                    style={styles.input}
                    required
                  />
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Instructor 2 */}
        {instructoresVisibles.segundoInstructor && (
          <div style={styles.instructorBox}>
            <h4 style={styles.instructorTitle}>Instructor {instructoresVisibles.segundoInstructor}</h4>
            
            <div style={styles.formGroup}>
              <label style={styles.label}>Nombre Completo:</label>
              <input
                type="text"
                value={campesenaData.instructores[1]?.nombre || ''}
                onChange={(e) => handleCampesenaChange(e, 1, 'nombre')}
                style={styles.input}
                placeholder="Nombre completo"
                required
              />
            </div>

            <div style={styles.row}>
              <div style={styles.half}>
                <label style={styles.label}>Correo:</label>
                <input
                  type="email"
                  value={campesenaData.instructores[1]?.correo || ''}
                  onChange={(e) => handleCampesenaChange(e, 1, 'correo')}
                  style={styles.input}
                  placeholder="correo@ejemplo.com"
                  required
                />
              </div>
              <div style={styles.half}>
                <label style={styles.label}>Celular:</label>
                <input
                  type="tel"
                  value={campesenaData.instructores[1]?.celular || ''}
                  onChange={(e) => handleCampesenaChange(e, 1, 'celular')}
                  style={styles.input}
                  placeholder="3001234567"
                  required
                />
              </div>
            </div>

            <h5 style={styles.fechasTitle}>Fechas de Formación (Meses 1-5)</h5>
            <div style={styles.fechasGrid}>
              {[1, 2, 3, 4, 5].map((mes) => (
                <div key={mes} style={styles.fechaBox}>
                  <label style={styles.label}>Mes {mes}:</label>
                  <input
                    type="date"
                    value={campesenaData.instructores[1]?.fechas[mes-1] || ''}
                    onChange={(e) => handleFechaChange(e, 1, mes-1)}
                    style={styles.input}
                    required
                  />
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

const styles = {
  container: {
    width: '100%'
  },
  section: {
    backgroundColor: '#f8f9fa',
    padding: '20px',
    borderRadius: '8px',
    marginBottom: '25px',
    border: '1px solid #e0e0e0'
